     1→const express = require('express');
     2→const fs = require('fs');
     3→const path = require('path');
     4→const helmet = require('helmet');
     5→const rateLimit = require('express-rate-limit');
     6→const multer = require('multer');
     7→const Database = require('better-sqlite3');
     8→const bcrypt = require('bcrypt');
     9→const crypto = require('crypto');
    10→
    11→const app = express();
    12→const PORT = process.env.PORT || 3400;
    13→const SALT_ROUNDS = 12;
    14→
    15→// Paths
    16→const DATA_DIR = path.join(__dirname, '../data');
    17→const CARDS_DIR = path.join(DATA_DIR, 'cards');
    18→const CALLSIGNS_FILE = path.join(DATA_DIR, 'callsigns.json');
    19→const DB_FILE = path.join(DATA_DIR, 'users.db');
    20→
    21→// Ensure directories exist
    22→if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    23→if (!fs.existsSync(CARDS_DIR)) fs.mkdirSync(CARDS_DIR, { recursive: true });
    24→
    25→// Initialize callsigns.json if not exists
    26→if (!fs.existsSync(CALLSIGNS_FILE)) {
    27→  fs.writeFileSync(CALLSIGNS_FILE, JSON.stringify({ callsigns: [] }, null, 2));
    28→}
    29→
    30→// Initialize SQLite database
    31→const db = new Database(DB_FILE);
    32→db.pragma('journal_mode = WAL');
    33→
    34→// Create users table
    35→db.exec(`
    36→  CREATE TABLE IF NOT EXISTS users (
    37→    id INTEGER PRIMARY KEY AUTOINCREMENT,
    38→    username TEXT UNIQUE NOT NULL,
    39→    password_hash TEXT NOT NULL,
    40→    callsign TEXT,
    41→    is_admin INTEGER DEFAULT 0,
    42→    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    43→    last_login TEXT
    44→  );
    45→
    46→  CREATE TABLE IF NOT EXISTS sessions (
    47→    token TEXT PRIMARY KEY,
    48→    user_id INTEGER NOT NULL,
    49→    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    50→    expires_at TEXT NOT NULL,
    51→    FOREIGN KEY (user_id) REFERENCES users(id)
    52→  );
    53→
    54→  CREATE INDEX IF NOT EXISTS idx_sessions_token ON sessions(token);
    55→  CREATE INDEX IF NOT EXISTS idx_users_callsign ON users(callsign);
    56→
    57→  CREATE TABLE IF NOT EXISTS audit_log (
    58→    id INTEGER PRIMARY KEY AUTOINCREMENT,
    59→    timestamp TEXT DEFAULT CURRENT_TIMESTAMP,
    60→    user_id INTEGER,
    61→    username TEXT,
    62→    callsign TEXT,
    63→    action TEXT NOT NULL,
    64→    details TEXT,
    65→    ip_address TEXT
    66→  );
    67→
    68→  CREATE INDEX IF NOT EXISTS idx_audit_timestamp ON audit_log(timestamp);
    69→  CREATE INDEX IF NOT EXISTS idx_audit_callsign ON audit_log(callsign);
    70→`);
    71→
    72→// Security headers
    73→app.use(helmet({
    74→  contentSecurityPolicy: false,
    75→  crossOriginEmbedderPolicy: false
    76→}));
    77→
    78→// Parse JSON bodies
    79→app.use(express.json());
    80→
    81→// Rate limiting
    82→const apiLimiter = rateLimit({
    83→  windowMs: 1 * 60 * 1000,
    84→  max: 100,
    85→  message: { error: 'Too many requests' }
    86→});
    87→
    88→const authLimiter = rateLimit({
    89→  windowMs: 15 * 60 * 1000, // 15 minutes
    90→  max: 10, // 10 attempts per 15 min
    91→  message: { error: 'Too many login attempts, try again later' }
    92→});
    93→
    94→// File upload configuration
    95→const storage = multer.diskStorage({
    96→  destination: (req, file, cb) => {
    97→    const callsign = req.params.callsign.toLowerCase();
    98→    const type = req.params.type;
    99→    let dir;
   100→
   101→    if (type === 'card') {
   102→      dir = path.join(CARDS_DIR, callsign);
   103→    } else {
   104→      dir = path.join(CARDS_DIR, callsign, 'backgrounds');
   105→    }
   106→
   107→    if (!fs.existsSync(dir)) {
   108→      fs.mkdirSync(dir, { recursive: true });
   109→    }
   110→    cb(null, dir);
   111→  },
   112→  filename: (req, file, cb) => {
   113→    if (req.params.type === 'card') {
   114→      cb(null, 'card.png');
   115→    } else {
   116→      const safeName = file.originalname.replace(/[^a-zA-Z0-9._-]/g, '_').toLowerCase();
   117→      cb(null, safeName);
   118→    }
   119→  }
   120→});
   121→
   122→const upload = multer({
   123→  storage,
   124→  limits: { fileSize: 10 * 1024 * 1024 },
   125→  fileFilter: (req, file, cb) => {
   126→    if (file.mimetype.startsWith('image/')) {
   127→      cb(null, true);
   128→    } else {
   129→      cb(new Error('Only images allowed'), false);
   130→    }
   131→  }
   132→});
