   134→// ============================================
   135→// Helper functions
   136→// ============================================
   137→
   138→function loadCallsigns() {
   139→  try {
   140→    return JSON.parse(fs.readFileSync(CALLSIGNS_FILE, 'utf8'));
   141→  } catch {
   142→    return { callsigns: [] };
   143→  }
   144→}
   145→
   146→function saveCallsigns(data) {
   147→  fs.writeFileSync(CALLSIGNS_FILE, JSON.stringify(data, null, 2));
   148→}
   149→
   150→function getCallsignConfig(callsign) {
   151→  const data = loadCallsigns();
   152→  return data.callsigns.find(c => c.id.toLowerCase() === callsign.toLowerCase());
   153→}
   154→
   155→function generateToken() {
   156→  return crypto.randomBytes(32).toString('hex');
   157→}
   158→
   159→function createSession(userId) {
   160→  const token = generateToken();
   161→  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(); // 7 days
   162→
   163→  db.prepare('INSERT INTO sessions (token, user_id, expires_at) VALUES (?, ?, ?)').run(token, userId, expiresAt);
   164→  return token;
   165→}
   166→
   167→function validateSession(token) {
   168→  if (!token) return null;
   169→
   170→  const session = db.prepare(`
   171→    SELECT s.*, u.username, u.callsign, u.is_admin
   172→    FROM sessions s
   173→    JOIN users u ON s.user_id = u.id
   174→    WHERE s.token = ? AND s.expires_at > datetime('now')
   175→  `).get(token);
   176→
   177→  return session;
   178→}
   179→
   180→function cleanExpiredSessions() {
   181→  db.prepare("DELETE FROM sessions WHERE expires_at < datetime('now')").run();
   182→}
   183→
   184→// Clean expired sessions periodically
   185→setInterval(cleanExpiredSessions, 60 * 60 * 1000); // Every hour
   186→
   187→// Audit logging
   188→function logAudit(req, action, details = null) {
   189→  const ip = req.ip || req.connection?.remoteAddress || 'unknown';
   190→  const userId = req.user?.user_id || null;
   191→  const username = req.user?.username || null;
   192→  const callsign = req.user?.callsign || req.params?.callsign || null;
   193→
   194→  db.prepare(`
   195→    INSERT INTO audit_log (user_id, username, callsign, action, details, ip_address)
   196→    VALUES (?, ?, ?, ?, ?, ?)
   197→  `).run(userId, username, callsign, action, details, ip);
   198→}
   199→
   200→// ============================================
   201→// Authentication middleware
   202→// ============================================
   203→
   204→function requireAuth(req, res, next) {
   205→  const token = req.headers['authorization']?.replace('Bearer ', '');
   206→  const session = validateSession(token);
   207→
   208→  if (!session) {
   209→    return res.status(401).json({ error: 'Unauthorized' });
   210→  }
   211→
   212→  req.user = session;
   213→  next();
   214→}
   215→
   216→function requireAdmin(req, res, next) {
   217→  if (!req.user.is_admin) {
   218→    return res.status(403).json({ error: 'Admin access required' });
   219→  }
   220→  next();
   221→}
   222→
   223→function requireCallsignAccess(req, res, next) {
   224→  const targetCallsign = req.params.callsign?.toLowerCase();
   225→
   226→  // Admins can access all callsigns
   227→  if (req.user.is_admin) {
   228→    return next();
   229→  }
   230→
   231→  // Users can only access their own callsign
   232→  if (req.user.callsign?.toLowerCase() !== targetCallsign) {
   233→    return res.status(404).json({ error: 'Not found' });
   234→  }
   235→
   236→  next();
   237→}
