   251→app.use(express.static(path.join(__dirname, '../public')));
   252→// Note: /cards is NOT served statically - protected endpoints below
   253→
   254→// ============================================
   255→// Public API Routes (limited)
   256→// ============================================
   257→
   258→// Get specific callsign configuration (used by admin)
   259→app.get('/api/callsigns/:callsign', apiLimiter, (req, res) => {
   260→  const callsign = req.params.callsign.toLowerCase();
   261→  const config = getCallsignConfig(callsign);
   262→
   263→  if (!config) {
   264→    return res.status(404).json({ error: 'Callsign not found' });
   265→  }
   266→
   267→  res.json(config);
   268→});
   269→
   270→// Get backgrounds for a callsign
   271→app.get('/api/callsigns/:callsign/backgrounds', apiLimiter, (req, res) => {
   272→  const callsign = req.params.callsign.toLowerCase();
   273→  const bgDir = path.join(CARDS_DIR, callsign, 'backgrounds');
   274→
   275→  if (!fs.existsSync(bgDir)) {
   276→    return res.json([]);
   277→  }
   278→
   279→  try {
   280→    const files = fs.readdirSync(bgDir)
   281→      .filter(f => /\.(jpg|jpeg|png|gif|webp)$/i.test(f))
   282→      .map(f => {
   283→        const name = path.parse(f).name;
   284→        const displayName = name
   285→          .replace(/[_-]/g, ' ')
   286→          .replace(/\d+$/, m => ' ' + m)
   287→          .split(' ')
   288→          .map(w => w.charAt(0).toUpperCase() + w.slice(1))
   289→          .join(' ')
   290→          .trim();
   291→        return { filename: f, displayName };
   292→      })
   293→      .sort((a, b) => a.displayName.localeCompare(b.displayName));
   294→
   295→    res.json(files);
   296→  } catch (err) {
   297→    res.status(500).json({ error: 'Failed to list backgrounds' });
   298→  }
   299→});
