   301→// ============================================
   302→// Authentication API
   303→// ============================================
   304→
   305→// Login
   306→app.post('/api/auth/login', authLimiter, async (req, res) => {
   307→  const { username, password } = req.body;
   308→
   309→  if (!username || !password) {
   310→    return res.status(400).json({ error: 'Username and password required' });
   311→  }
   312→
   313→  const user = db.prepare('SELECT * FROM users WHERE username = ?').get(username.toLowerCase());
   314→
   315→  if (!user) {
   316→    return res.status(401).json({ error: 'Invalid credentials' });
   317→  }
   318→
   319→  const valid = await bcrypt.compare(password, user.password_hash);
   320→  if (!valid) {
   321→    return res.status(401).json({ error: 'Invalid credentials' });
   322→  }
   323→
   324→  // Update last login
   325→  db.prepare('UPDATE users SET last_login = ? WHERE id = ?').run(new Date().toISOString(), user.id);
   326→
   327→  const token = createSession(user.id);
   328→
   329→  res.json({
   330→    token,
   331→    user: {
   332→      username: user.username,
   333→      callsign: user.callsign,
   334→      isAdmin: !!user.is_admin
   335→    }
   336→  });
   337→});
   338→
   339→// Logout
   340→app.post('/api/auth/logout', requireAuth, (req, res) => {
   341→  const token = req.headers['authorization']?.replace('Bearer ', '');
   342→  db.prepare('DELETE FROM sessions WHERE token = ?').run(token);
   343→  res.json({ success: true });
   344→});
   345→
   346→// Get current user
   347→app.get('/api/auth/me', requireAuth, (req, res) => {
   348→  res.json({
   349→    username: req.user.username,
   350→    callsign: req.user.callsign,
   351→    isAdmin: !!req.user.is_admin
   352→  });
   353→});
   354→
   355→// Change password
   356→app.post('/api/auth/change-password', requireAuth, async (req, res) => {
   357→  const { currentPassword, newPassword } = req.body;
   358→
   359→  if (!currentPassword || !newPassword) {
   360→    return res.status(400).json({ error: 'Current and new password required' });
   361→  }
   362→
   363→  if (newPassword.length < 8) {
   364→    return res.status(400).json({ error: 'Password must be at least 8 characters' });
   365→  }
   366→
   367→  const user = db.prepare('SELECT * FROM users WHERE id = ?').get(req.user.user_id);
   368→  const valid = await bcrypt.compare(currentPassword, user.password_hash);
   369→
   370→  if (!valid) {
   371→    return res.status(401).json({ error: 'Current password is incorrect' });
   372→  }
   373→
   374→  const hash = await bcrypt.hash(newPassword, SALT_ROUNDS);
   375→  db.prepare('UPDATE users SET password_hash = ? WHERE id = ?').run(hash, user.id);
   376→
   377→  // Invalidate all sessions except current
   378→  const token = req.headers['authorization']?.replace('Bearer ', '');
   379→  db.prepare('DELETE FROM sessions WHERE user_id = ? AND token != ?').run(user.id, token);
   380→
   381→  res.json({ success: true });
   382→});
