   386→// ============================================
   387→
   388→// Get own callsign config
   389→app.get('/api/manage/callsign', requireAuth, (req, res) => {
   390→  if (!req.user.callsign) {
   391→    return res.status(403).json({ error: 'No callsign assigned to your account' });
   392→  }
