   402→// Get own backgrounds
   403→app.get('/api/manage/backgrounds', requireAuth, (req, res) => {
   404→  if (!req.user.callsign) {
   405→    return res.status(403).json({ error: 'No callsign assigned to your account' });
   406→  }
