   435→
   436→// Update own callsign config
   437→app.put('/api/manage/callsign', requireAuth, (req, res) => {
   438→  if (!req.user.callsign) {
   439→    return res.status(403).json({ error: 'No callsign assigned to your account' });
   440→  }
   441→
   442→  const callsign = req.user.callsign.toLowerCase();
   443→  const data = loadCallsigns();
   444→  const index = data.callsigns.findIndex(c => c.id.toLowerCase() === callsign);
   445→
   446→  if (index === -1) {
   447→    return res.status(404).json({ error: 'Callsign not found' });
