   496→// ============================================
   497→// Admin API Routes
   498→// ============================================
   499→
   500→// List all users (admin only)
   501→app.get('/api/admin/users', requireAuth, requireAdmin, (req, res) => {
   502→  const users = db.prepare(`
   503→    SELECT id, username, callsign, is_admin, created_at, last_login
   504→    FROM users ORDER BY username
   505→  `).all();
   506→
   507→  res.json(users.map(u => ({
   508→    ...u,
   509→    isAdmin: !!u.is_admin
   510→  })));
   511→});
   512→
   513→// Create user (admin only)
   514→app.post('/api/admin/users', requireAuth, requireAdmin, async (req, res) => {
   515→  const { username, password, callsign, isAdmin } = req.body;
   516→
   517→  if (!username || !password) {
   518→    return res.status(400).json({ error: 'Username and password required' });
   519→  }
   520→
   521→  if (password.length < 8) {
   522→    return res.status(400).json({ error: 'Password must be at least 8 characters' });
   523→  }
   524→
   525→  const existing = db.prepare('SELECT id FROM users WHERE username = ?').get(username.toLowerCase());
   526→  if (existing) {
   527→    return res.status(409).json({ error: 'Username already exists' });
   528→  }
   529→
   530→  // If callsign specified, verify it exists
   531→  if (callsign) {
   532→    const csConfig = getCallsignConfig(callsign);
   533→    if (!csConfig) {
   534→      return res.status(400).json({ error: 'Callsign does not exist. Create it first.' });
   535→    }
   536→
   537→    // Check if callsign is already assigned
   538→    const assigned = db.prepare('SELECT id FROM users WHERE callsign = ?').get(callsign.toLowerCase());
   539→    if (assigned) {
   540→      return res.status(409).json({ error: 'Callsign already assigned to another user' });
   541→    }
   542→  }
   543→
   544→  const hash = await bcrypt.hash(password, SALT_ROUNDS);
   545→  const result = db.prepare(`
   546→    INSERT INTO users (username, password_hash, callsign, is_admin)
   547→    VALUES (?, ?, ?, ?)
   548→  `).run(username.toLowerCase(), hash, callsign?.toLowerCase() || null, isAdmin ? 1 : 0);
   549→
   550→  res.status(201).json({
   551→    id: result.lastInsertRowid,
   552→    username: username.toLowerCase(),
   553→    callsign: callsign?.toLowerCase() || null,
   554→    isAdmin: !!isAdmin
   555→  });
   556→});
   557→
   558→// Update user (admin only)
   559→app.put('/api/admin/users/:id', requireAuth, requireAdmin, async (req, res) => {
   560→  const userId = parseInt(req.params.id);
   561→  const { password, callsign, isAdmin } = req.body;
   562→
   563→  const user = db.prepare('SELECT * FROM users WHERE id = ?').get(userId);
   564→  if (!user) {
   565→    return res.status(404).json({ error: 'User not found' });
   566→  }
   567→
   568→  if (password) {
   569→    if (password.length < 8) {
   570→      return res.status(400).json({ error: 'Password must be at least 8 characters' });
   571→    }
   572→    const hash = await bcrypt.hash(password, SALT_ROUNDS);
   573→    db.prepare('UPDATE users SET password_hash = ? WHERE id = ?').run(hash, userId);
   574→  }
   575→
   576→  if (callsign !== undefined) {
   577→    if (callsign) {
   578→      // Check if callsign is assigned to another user
   579→      const assigned = db.prepare('SELECT id FROM users WHERE callsign = ? AND id != ?').get(callsign.toLowerCase(), userId);
   580→      if (assigned) {
   581→        return res.status(409).json({ error: 'Callsign already assigned to another user' });
   582→      }
   583→    }
   584→    db.prepare('UPDATE users SET callsign = ? WHERE id = ?').run(callsign?.toLowerCase() || null, userId);
   585→  }
   586→
   587→  if (isAdmin !== undefined) {
   588→    db.prepare('UPDATE users SET is_admin = ? WHERE id = ?').run(isAdmin ? 1 : 0, userId);
   589→  }
   590→
   591→  const updated = db.prepare('SELECT id, username, callsign, is_admin FROM users WHERE id = ?').get(userId);
   592→  res.json({ ...updated, isAdmin: !!updated.is_admin });
   593→});
   594→
   595→// Delete user (admin only)
   596→app.delete('/api/admin/users/:id', requireAuth, requireAdmin, (req, res) => {
   597→  const userId = parseInt(req.params.id);
   598→
   599→  // Prevent self-deletion
   600→  if (userId === req.user.user_id) {
   601→    return res.status(400).json({ error: 'Cannot delete your own account' });
   602→  }
   603→
   604→  const result = db.prepare('DELETE FROM users WHERE id = ?').run(userId);
