     1→/**
     2→ * Internationalization (i18n) Module for QSL Card Generator
     3→ * Supports German (de) and English (en) with localStorage persistence
     4→ */
     5→
     6→const i18n = (function() {
     7→  const SUPPORTED_LANGS = ['de', 'en'];
     8→  const DEFAULT_LANG = 'en';
     9→  const STORAGE_KEY = 'qsl_language';
    10→
    11→  let currentLang = DEFAULT_LANG;
    12→  let translations = {};
    13→  let initialized = false;
    14→
    15→  /**
    16→   * Detect user's preferred language
    17→   */
    18→  function detectLanguage() {
    19→    // 1. Check localStorage
    20→    const stored = localStorage.getItem(STORAGE_KEY);
    21→    if (stored && SUPPORTED_LANGS.includes(stored)) {
    22→      return stored;
    23→    }
    24→
    25→    // 2. Check browser language
    26→    const browserLang = navigator.language?.split('-')[0];
    27→    if (browserLang && SUPPORTED_LANGS.includes(browserLang)) {
    28→      return browserLang;
    29→    }
    30→
    31→    // 3. Fallback to default
    32→    return DEFAULT_LANG;
    33→  }
    34→
    35→  /**
    36→   * Load translation file for a language
    37→   */
    38→  async function loadLocale(lang) {
    39→    try {
    40→      const response = await fetch(`/locales/${lang}.json`);
    41→      if (!response.ok) throw new Error(`Failed to load ${lang}.json`);
    42→      return await response.json();
    43→    } catch (error) {
    44→      console.error(`i18n: Failed to load locale ${lang}:`, error);
    45→      return null;
    46→    }
    47→  }
    48→
    49→  /**
    50→   * Get nested value from object using dot notation
    51→   */
    52→  function getNestedValue(obj, path) {
    53→    return path.split('.').reduce((current, key) => {
    54→      return current && current[key] !== undefined ? current[key] : null;
    55→    }, obj);
    56→  }
    57→
    58→  /**
    59→   * Translate a key with optional parameter substitution
    60→   * @param {string} key - Dot notation key (e.g., 'auth.signIn')
    61→   * @param {object} params - Optional parameters for substitution (e.g., {name: 'John'})
    62→   * @returns {string} Translated text or key if not found
    63→   */
    64→  function t(key, params = {}) {
    65→    let text = getNestedValue(translations, key);
    66→
    67→    if (text === null) {
    68→      console.warn(`i18n: Missing translation for key: ${key}`);
    69→      return key;
    70→    }
    71→
    72→    // Parameter substitution: {{param}}
    73→    if (params && typeof text === 'string') {
    74→      Object.keys(params).forEach(param => {
    75→        text = text.replace(new RegExp(`{{${param}}}`, 'g'), params[param]);
    76→      });
    77→    }
    78→
    79→    return text;
    80→  }
    81→
    82→  /**
    83→   * Apply translations to all elements with data-i18n attribute
    84→   */
    85→  function applyTranslations() {
    86→    document.querySelectorAll('[data-i18n]').forEach(el => {
    87→      const key = el.getAttribute('data-i18n');
    88→      const translated = t(key);
    89→
    90→      // Handle different element types
    91→      if (el.tagName === 'INPUT' && el.type !== 'submit' && el.type !== 'button') {
    92→        if (el.placeholder !== undefined && el.getAttribute('data-i18n-placeholder')) {
    93→          el.placeholder = t(el.getAttribute('data-i18n-placeholder'));
    94→        }
    95→      } else if (el.tagName === 'OPTION') {
    96→        el.textContent = translated;
    97→      } else {
    98→        // Use innerHTML if translation contains HTML tags, otherwise use textContent
    99→        if (translated.includes('<') && translated.includes('>')) {
   100→          el.innerHTML = translated;
   101→        } else {
   102→          el.textContent = translated;
   103→        }
   104→      }
   105→    });
   106→
   107→    // Handle placeholder attributes separately
   108→    document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
   109→      const key = el.getAttribute('data-i18n-placeholder');
   110→      el.placeholder = t(key);
   111→    });
   112→
   113→    // Handle title attributes
   114→    document.querySelectorAll('[data-i18n-title]').forEach(el => {
   115→      const key = el.getAttribute('data-i18n-title');
   116→      el.title = t(key);
   117→    });
   118→
   119→    // Update HTML lang attribute
   120→    document.documentElement.lang = currentLang;
   121→
   122→    // Update language switcher if present
   123→    const langSwitch = document.getElementById('langSwitch');
   124→    if (langSwitch) {
   125→      langSwitch.value = currentLang;
   126→    }
   127→  }
   128→
   129→  /**
   130→   * Set the current language
   131→   * @param {string} lang - Language code ('de' or 'en')
   132→   */
   133→  async function setLanguage(lang) {
   134→    if (!SUPPORTED_LANGS.includes(lang)) {
   135→      console.warn(`i18n: Unsupported language: ${lang}`);
   136→      return false;
   137→    }
   138→
   139→    const newTranslations = await loadLocale(lang);
   140→    if (!newTranslations) {
   141→      return false;
   142→    }
   143→
   144→    translations = newTranslations;
   145→    currentLang = lang;
   146→    localStorage.setItem(STORAGE_KEY, lang);
   147→
   148→    applyTranslations();
   149→
   150→    // Dispatch custom event for components that need to react
   151→    window.dispatchEvent(new CustomEvent('languagechange', { detail: { lang } }));
   152→
   153→    return true;
   154→  }
   155→
   156→  /**
   157→   * Initialize the i18n module
   158→   */
   159→  async function init() {
   160→    if (initialized) return currentLang;
   161→
   162→    currentLang = detectLanguage();
   163→    translations = await loadLocale(currentLang);
   164→
   165→    if (!translations) {
   166→      // Fallback to default if detected language fails
   167→      if (currentLang !== DEFAULT_LANG) {
   168→        currentLang = DEFAULT_LANG;
   169→        translations = await loadLocale(DEFAULT_LANG);
   170→      }
   171→    }
   172→
   173→    if (!translations) {
   174→      console.error('i18n: Failed to load any translations');
   175→      translations = {};
   176→    }
   177→
   178→    initialized = true;
   179→    applyTranslations();
   180→
   181→    return currentLang;
   182→  }
   183→
   184→  /**
   185→   * Get current language
   186→   */
   187→  function getLanguage() {
   188→    return currentLang;
   189→  }
   190→
   191→  /**
   192→   * Get all supported languages
   193→   */
   194→  function getSupportedLanguages() {
   195→    return [...SUPPORTED_LANGS];
   196→  }
   197→
   198→  /**
   199→   * Check if initialized
   200→   */
   201→  function isInitialized() {
   202→    return initialized;
   203→  }
   204→
   205→  // Public API
   206→  return {
   207→    init,
   208→    t,
   209→    setLanguage,
   210→    getLanguage,
   211→    getSupportedLanguages,
   212→    applyTranslations,
   213→    isInitialized
   214→  };
   215→})();
   216→
   217→// Export for module environments
   218→if (typeof module !== 'undefined' && module.exports) {
   219→  module.exports = i18n;
   220→}
   221→

