   539→  <script>
   540→    const pathParts = window.location.pathname.split('/').filter(Boolean);
   541→    const CALLSIGN = pathParts[0] || '';
   542→
   543→    let token = localStorage.getItem('authToken') || '';
   544→    let currentUser = null;
   545→    let config = null;
   546→    let positions = null;
   547→    const SCALE_FACTOR = 0.4;
   548→
   549→    // Initialize i18n
   550→    document.addEventListener('DOMContentLoaded', async () => {
   551→      await i18n.init();
   552→      updateLangButtons();
   553→      // Set default remarks
   554→      document.getElementById('additional').value = i18n.t('generator.defaultRemarks');
   555→    });
   556→
   557→    function switchLang(lang) {
   558→      i18n.setLanguage(lang);
   559→      updateLangButtons();
   560→      // Update default remarks if empty or default value
   561→      const additionalEl = document.getElementById('additional');
   562→      const currentVal = additionalEl.value;
   563→      if (currentVal === 'Thanks for the QSO\nBest regards' || currentVal === 'Danke für das QSO\nBeste Grüße') {
   564→        additionalEl.value = i18n.t('generator.defaultRemarks');
   565→      }
   566→    }
   567→
   568→    function updateLangButtons() {
   569→      const lang = i18n.getLanguage();
   570→      document.getElementById('langDe').classList.toggle('active', lang === 'de');
   571→      document.getElementById('langEn').classList.toggle('active', lang === 'en');
   572→    }
   573→
   574→    const canvas = document.getElementById('qslCanvas');
   575→    const ctx = canvas.getContext('2d');
   576→    const cardImage = new Image();
   577→    const backgroundImage = new Image();
   578→
   579→    async function apiCall(url, options = {}) {
   580→      options.headers = { ...options.headers, 'Authorization': `Bearer ${token}` };
   581→      return fetch(url, options);
   582→    }
   583→
   584→    async function checkAccess() {
   585→      if (!token) {
   586→        showAuth();
   587→        return;
   588→      }
   589→
   590→      try {
   591→        const meResponse = await apiCall('/api/auth/me');
   592→        if (!meResponse.ok) {
   593→          token = '';
   594→          localStorage.removeItem('authToken');
   595→          showAuth();
   596→          return;
   597→        }
   598→
   599→        currentUser = await meResponse.json();
   600→        const accessResponse = await apiCall(`/api/generator/${CALLSIGN}/access`);
   601→
   602→        if (!accessResponse.ok) {
   603→          window.location.href = '/';
   604→          return;
   605→        }
   606→
   607→        config = await accessResponse.json();
   608→        positions = config.textPositions;
   609→        await loadGenerator();
   610→      } catch (error) {
   611→        console.error('Access check failed:', error);
   612→        showAuth();
   613→      }
   614→    }
   615→
   616→    function showAuth() {
   617→      document.getElementById('loadingOverlay').style.display = 'none';
   618→      document.getElementById('authOverlay').style.display = 'flex';
   619→      document.getElementById('mainContent').style.display = 'none';
   620→    }
   621→
   622→    async function login(e) {
   623→      e.preventDefault();
   624→      const username = document.getElementById('loginUsername').value.trim();
   625→      const password = document.getElementById('loginPassword').value;
   626→
   627→      try {
   628→        const response = await fetch('/api/auth/login', {
   629→          method: 'POST',
   630→          headers: { 'Content-Type': 'application/json' },
   631→          body: JSON.stringify({ username, password })
   632→        });
   633→
   634→        const data = await response.json();
   635→        if (response.ok) {
   636→          token = data.token;
   637→          currentUser = data.user;
   638→          localStorage.setItem('authToken', token);
   639→          checkAccess();
   640→        } else {
   641→          showAuthError(data.error || i18n.t('errors.loginFailed'));
   642→        }
   643→      } catch (e) {
   644→        showAuthError(i18n.t('errors.connectionError'));
   645→      }
   646→    }
   647→
   648→    function logout() {
   649→      apiCall('/api/auth/logout', { method: 'POST' }).catch(() => {});
   650→      localStorage.removeItem('authToken');
   651→      window.location.href = '/';
   652→    }
   653→
   654→    function showAuthError(msg) {
   655→      const el = document.getElementById('authError');
   656→      el.textContent = msg;
   657→      el.style.display = 'block';
   658→    }
   659→
   660→    async function loadGenerator() {
   661→      document.getElementById('currentUser').textContent = currentUser.username;
   662→      document.getElementById('topbarCallsign').textContent = config.id.toUpperCase();
   663→      document.getElementById('stationName').textContent = config.name;
   664→      document.getElementById('qrzLink').href = config.qrzLink;
   665→      document.title = `QSL Card - ${config.id.toUpperCase()}`;
   666→
   667→      await loadBackgrounds();
   668→      loadCardImage();
   669→
   670→      document.getElementById('loadingOverlay').style.display = 'none';
   671→      document.getElementById('authOverlay').style.display = 'none';
   672→      document.getElementById('mainContent').style.display = 'block';
   673→    }
   674→
   675→    async function loadAuthenticatedImage(img, url) {
   676→      try {
   677→        const response = await apiCall(url);
   678→        if (!response.ok) throw new Error('Failed to load image');
   679→        const blob = await response.blob();
   680→        img.src = URL.createObjectURL(blob);
   681→      } catch (error) {
   682→        console.error('Failed to load image:', error);
   683→      }
   684→    }
