     1→#!/usr/bin/env node
     2→/**
     3→ * Migration script to import callsigns from the old qslgeneratorold directory
     4→ * Run: node scripts/migrate.js /path/to/qslgeneratorold
     5→ */
     6→
     7→const fs = require('fs');
     8→const path = require('path');
     9→
    10→const SOURCE_DIR = process.argv[2] || '/home/oe8yml/qslgeneratorold';
    11→const DATA_DIR = path.join(__dirname, '../data');
    12→const CARDS_DIR = path.join(DATA_DIR, 'cards');
    13→const CALLSIGNS_FILE = path.join(DATA_DIR, 'callsigns.json');
    14→
    15→// Default text positions (from oe8cni.htm)
    16→const DEFAULT_POSITIONS = {
    17→  callsign: { x: 3368, y: 2026 },
    18→  utcDateTime: { x: 2623, y: 2499 },
    19→  frequency: { x: 3398, y: 2499 },
    20→  mode: { x: 3906, y: 2499 },
    21→  rst: { x: 4353, y: 2499 },
    22→  additional: { x: 2027, y: 2760 }
    23→};
    24→
    25→// Ensure directories exist
    26→if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    27→if (!fs.existsSync(CARDS_DIR)) fs.mkdirSync(CARDS_DIR, { recursive: true });
    28→
    29→// Load existing callsigns
    30→let callsignsData = { callsigns: [] };
    31→if (fs.existsSync(CALLSIGNS_FILE)) {
    32→  callsignsData = JSON.parse(fs.readFileSync(CALLSIGNS_FILE, 'utf8'));
    33→}
    34→
    35→// Get all directories in source
    36→const entries = fs.readdirSync(SOURCE_DIR, { withFileTypes: true });
    37→const callsignDirs = entries.filter(e => e.isDirectory() && !e.name.startsWith('.'));
    38→
    39→console.log(`Found ${callsignDirs.length} potential callsign directories\n`);
    40→
    41→let migrated = 0;
    42→let skipped = 0;
    43→
    44→for (const dir of callsignDirs) {
    45→  const sourcePath = path.join(SOURCE_DIR, dir.name);
    46→
    47→  // Extract callsign from directory name (format: callsign_hash)
    48→  const callsignMatch = dir.name.match(/^([a-z0-9]+)_/i);
    49→  if (!callsignMatch) {
    50→    // Try without underscore (like oe0test)
    51→    if (!dir.name.match(/^[a-z0-9]+$/i)) {
    52→      console.log(`Skipping ${dir.name} - invalid format`);
    53→      skipped++;
    54→      continue;
    55→    }
    56→  }
    57→
    58→  const callsignId = callsignMatch ? callsignMatch[1].toLowerCase() : dir.name.toLowerCase();
    59→
    60→  // Check if card.png exists (or similar)
    61→  const cardFiles = fs.readdirSync(sourcePath).filter(f =>
    62→    f.toLowerCase().includes('card') && f.endsWith('.png')
    63→  );
    64→
    65→  if (cardFiles.length === 0) {
    66→    console.log(`Skipping ${dir.name} - no card template found`);
    67→    skipped++;
    68→    continue;
    69→  }
    70→
    71→  // Check if already exists
    72→  if (callsignsData.callsigns.find(c => c.id === callsignId)) {
    73→    console.log(`Skipping ${callsignId} - already exists`);
    74→    skipped++;
    75→    continue;
    76→  }
    77→
    78→  console.log(`Migrating ${callsignId}...`);
    79→
    80→  // Create destination directory
    81→  const destPath = path.join(CARDS_DIR, callsignId);
    82→  const bgDestPath = path.join(destPath, 'backgrounds');
    83→  if (!fs.existsSync(bgDestPath)) {
    84→    fs.mkdirSync(bgDestPath, { recursive: true });
    85→  }
    86→
    87→  // Copy card template (use first found)
    88→  const cardSource = path.join(sourcePath, cardFiles[0]);
    89→  const cardDest = path.join(destPath, 'card.png');
    90→  fs.copyFileSync(cardSource, cardDest);
    91→  console.log(`  - Copied card template: ${cardFiles[0]}`);
    92→
    93→  // Copy backgrounds
    94→  const bgSourcePath = path.join(sourcePath, 'background');
    95→  const bgSourcePath2 = path.join(sourcePath, 'backgrounds');
    96→  const actualBgPath = fs.existsSync(bgSourcePath) ? bgSourcePath :
    97→                       fs.existsSync(bgSourcePath2) ? bgSourcePath2 : null;
    98→
    99→  let bgCount = 0;
   100→  if (actualBgPath) {
   101→    const bgFiles = fs.readdirSync(actualBgPath).filter(f =>
   102→      /\.(jpg|jpeg|png|gif|webp)$/i.test(f)
   103→    );
   104→
   105→    for (const bgFile of bgFiles) {
   106→      const bgSrc = path.join(actualBgPath, bgFile);
   107→      const bgDst = path.join(bgDestPath, bgFile.toLowerCase());
   108→      fs.copyFileSync(bgSrc, bgDst);
   109→      bgCount++;
   110→    }
   111→    console.log(`  - Copied ${bgCount} backgrounds`);
   112→  }
   113→
   114→  // Add to callsigns.json
   115→  callsignsData.callsigns.push({
   116→    id: callsignId,
   117→    name: callsignId.toUpperCase(),
   118→    qrzLink: `https://www.qrz.com/db/${callsignId.toUpperCase()}`,
   119→    textPositions: DEFAULT_POSITIONS,
   120→    createdAt: new Date().toISOString(),
   121→    migratedFrom: dir.name
   122→  });
   123→
   124→  migrated++;
   125→  console.log(`  - Done!\n`);
   126→}
   127→
   128→// Save callsigns.json
   129→fs.writeFileSync(CALLSIGNS_FILE, JSON.stringify(callsignsData, null, 2));
   130→
   131→console.log(`\n========================================`);
   132→console.log(`Migration complete!`);
   133→console.log(`  Migrated: ${migrated}`);
   134→console.log(`  Skipped: ${skipped}`);
   135→console.log(`  Total callsigns: ${callsignsData.callsigns.length}`);
   136→console.log(`========================================\n`);
