node << 'EOFNODE'
const fs = require('fs');
const readline = require('readline');

const file = '/home/achildrenmile/.REDACTED.jsonl';

let measurements = [];
let codeSnippets = [];
let count = 0;

const rl = readline.createInterface({
  input: fs.createReadStream(file),
  crlfDelay: Infinity
});

rl.on('line', (line) => {
  try {
    const data = JSON.parse(line);
    if (data.content && typeof data.content === 'string') {
      const content = data.content;

      // Search for numbers followed by px, pixel, width, height, coordinate, font, position
      if (/\b(?:x|y|width|height|pixel|coordinate|font.?size|position)\s*[:=]\s*\d+|\d{2,4}\s*(?:px|pixel)/i.test(content)) {
        measurements.push(content.substring(0, 800));
      }

      // Search for canvas drawing code
      if (/(ctx\.|canvas\.|drawText|fillRect|fillStyle|fontSize|coordinate|\d{2,4}\s*,\s*\d{2,4})/i.test(content)) {
        codeSnippets.push(content.substring(0, 800));
      }
      count++;
    }
  } catch(e) {
    // Skip parse errors
  }
});

rl.on('close', () => {
  console.log('=== MEASUREMENTS FOUND ===\n');
  measurements.slice(0, 15).forEach((m, i) => {
    console.log(`${i+1}. ${m}\n`);
  });

  console.log('\n\n=== CODE SNIPPETS WITH COORDINATES ===\n');
  codeSnippets.slice(0, 15).forEach((s, i) => {
    console.log(`${i+1}. ${s}\n`);
  });

  console.log(`\nProcessed ${count} lines with content`);
});
